from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import secrets
import string
import smtplib
from email.mime.multipart import MIMEMultipart
from email.mime.text import MIMEText

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

limiter = Limiter(
    app,
    key_func=get_remote_address,
    default_limits=["200 per day", "50 per hour"]
)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    reset_token = db.Column(db.String(255), nullable=True)

@app.route('/password-reset', methods=['POST'])
@limiter.limit("5 per minute")
def password_reset():
    data = request.json
    if 'email' not in data or 'token' not in data:
        return jsonify({'error': 'Invalid request'}), 400

    user = User.query.filter_by(email=data['email']).first()
    if user and user.reset_token == data['token']:
        # Token is valid, allow password reset
        return jsonify({'message': 'Password reset successful'}), 200
    elif user:
        # Generate new token and send email
        token = ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(32))
        user.reset_token = token
        db.session.commit()
        send_reset_email(user.email, token)
        return jsonify({'message': 'Password reset link sent'}), 200
    else:
        # Create new user and generate token
        new_user = User(email=data['email'], reset_token=token)
        db.session.add(new_user)
        db.session.commit()
        send_reset_email(data['email'], token)
        return jsonify({'message': 'Password reset link sent'}), 200

def send_reset_email(email, token):
    msg = MIMEMultipart()
    msg['From'] = 'your-email@gmail.com'
    msg['To'] = email
    msg['Subject'] = 'Password Reset Link'

    body = f'To reset your password, click this link: http://example.com/reset-password?token={token}'
    msg.attach(MIMEText(body, 'plain'))

    server = smtplib.SMTP('smtp.gmail.com', 587)
    server.starttls()
    server.login(msg['From'], 'your-email-password')
    text = msg.as_string()
    server.sendmail(msg['From'], msg['To'], text)
    server.quit()

if __name__ == '__main__':
    app.run(debug=True)